function DistributionPanel({item,idea,update,notify}){let current=item.versions||{};const destinations=['Instagram Feed','Instagram Story','LinkedIn','Facebook','TikTok','X'];const[selected,setSelected]=useState(item.destinations||item.platforms);const[versions,setVersions]=useState(current);const toggle=p=>setSelected(selected.includes(p)?selected.filter(x=>x!==p):[...selected,p]);const sample=p=>p.includes('LinkedIn')?`${idea?.hook}\n\n${idea?.message}\n\nA practical way for commerce teams to create more without losing consistency.`:`${idea?.hook} ✨\n\n${idea?.message}\n\nCreate it. Refine it. Publish it.`;return <div className="distribution"><h3>Publishing destinations</h3><div className="chips">{destinations.map(p=><button className={selected.includes(p)?'selected':''} onClick={()=>toggle(p)}>{p}</button>)}</div>{selected.map(p=>{let v=versions[p]||{caption:sample(p),cta:'Learn more',hashtags:p.includes('LinkedIn')?'#AI #Ecommerce #CreativeOps':'#AIContent #ProductPhotography #Ecommerce',date:'',time:'10:00'};let set=(k,val)=>setVersions({...versions,[p]:{...v,[k]:val}});return <section><h3>{p}</h3><label>Caption<textarea value={v.caption} onChange={e=>set('caption',e.target.value)}/></label><div><label>CTA<input value={v.cta} onChange={e=>set('cta',e.target.value)}/></label><label>Hashtags<input value={v.hashtags} onChange={e=>set('hashtags',e.target.value)}/></label><label>Date<input type="date" value={v.date} onChange={e=>set('date',e.target.value)}/></label><label>Time<input type="time" value={v.time} onChange={e=>set('time',e.target.value)}/></label></div></section>})}<button className="primary" onClick={()=>{update({destinations:selected,versions,status:selected.some(p=>versions[p]?.date)?'Ready to Publish':item.status});notify('Platform versions saved')}}>Save platform versions</button></div>}
